mapper.select:
SELECT sr.id, sr.room_code AS roomCode, sr.room_name AS roomName, sr.display_name AS displayName, c.campus_name AS campus, b.building_name AS building, f.floor_name AS floor, o.org_name AS ownerOrganization, rt.room_type_name AS roomType, sr.total_capacity AS totalCapacity, sr.visibility_scope AS visibilityScope, sr.room_status AS roomStatus, sr.open_rule_type AS openRuleType, sr.location_detail AS locationDetail, sr.created_at AS createdAt, sr.campus_id AS campusId, sr.building_id AS buildingId, sr.floor_id AS floorId, sr.owner_organization_id AS ownerOrganizationId, sr.room_type_id AS roomTypeId FROM study_rooms sr JOIN campuses c ON c.id = sr.campus_id JOIN buildings b ON b.id = sr.building_id LEFT JOIN floors f ON f.id = sr.floor_id LEFT JOIN organizations o ON o.id = sr.owner_organization_id JOIN room_types rt ON rt.id = sr.room_type_id WHERE sr.deleted_at IS NULL
AND (sr.room_code LIKE CONCAT('%', #{q.search}, '%') OR sr.room_name LIKE CONCAT('%', #{q.search}, '%'))
AND c.campus_name = #{q.campus}
AND sr.visibility_scope = #{q.visibilityScope}
ORDER BY sr.created_at DESC
